void decimal_right_shift(decimal &h, uint32_t shift) {
  uint32_t read_index = 0;
  uint32_t write_index = 0;
  uint64_t n = 0;
  while ((n >> shift) == 0) {
    if (read_index < h.num_digits) {
      n = (10 * n) + h.digits[read_index++];
    } else if (n == 0) {
      return;
    } else {
      while ((n >> shift) == 0) {
        n = 10 * n;
        read_index++;
      }
      break;
    }
  }
  h.decimal_point -= int32_t(read_index - 1);
  if (h.decimal_point < -decimal_point_range) {
    // it is zero
    h.num_digits = 0;
    h.decimal_point = 0;
    h.negative = false;
    h.truncated = false;
    return;
  }
  uint64_t mask = (uint64_t(1) << shift) - 1;
  while (read_index < h.num_digits) {
    uint8_t new_digit = uint8_t(n >> shift);
    n = (10 * (n & mask)) + h.digits[read_index++];
    h.digits[write_index++] = new_digit;
  }
  while (n > 0) {
    uint8_t new_digit = uint8_t(n >> shift);
    n = 10 * (n & mask);
    if (write_index < max_digits) {
      h.digits[write_index++] = new_digit;
    } else if (new_digit > 0) {
      h.truncated = true;
    }
  }
  h.num_digits = write_index;
  trim(h);
}

const composeCleaner = ({
  schema,
  name,
  type,
  typeAlias = type,
  normalize,
  ignoreTryCatch = false
}: {
  schema: ElysiaTypeCheck<any>
  name: string
  type: keyof SchemaValidator
  typeAlias?: string
  normalize: ElysiaConfig<''>['normalize']
  ignoreTryCatch?: boolean
}) => {
  if (!normalize || !schema.Clean) return ''

  if (normalize === true || normalize === 'exactMirror') {
    if (ignoreTryCatch)
      return `${name}=validator.${typeAlias}.Clean(${name})\n`

    return (
      `try{` +
      `${name}=validator.${typeAlias}.Clean(${name})\n` +
      `}catch{}`
    )
  }

  if (normalize === 'typebox')
    return `${name}=validator.${typeAlias}.Clean(${name})\n`

  return ''
}

const normalizeValue = (
  define: DefinePluginOptions,
  supportsBigIntLiteral: boolean,
) => {
  const normalizePrimitive = (
    p: CodeValuePrimitive,
  ): NormalizedCodeValuePrimitive => {
    if (p === undefined) {
      return 'undefined';
    }
    if (Object.is(p, -0)) {
      return '-0';
    }
    if (p instanceof RegExp) {
      return p.toString();
    }
    if (typeof p === 'function') {
      return `(${p.toString()})`;
    }
    if (typeof p === 'bigint') {
      return supportsBigIntLiteral
        ? `${p}n`
        : `BigInt("${p}")`;
    }
    // assume `p` is a valid JSON value
    return p;
  };
  const normalizeObject = (
    define: CodeValue,
  ): NormalizedCodeValue => {
    if (Array.isArray(define)) {
      return define.map(normalizeObject);
    }
    if (define instanceof RegExp) {
      return normalizePrimitive(define);
    }
    if (define && typeof define === 'object') {
      const keys = Object.keys(define);
      return Object.fromEntries(
        keys.map((k) => [k, normalizeObject(define[k])]),
      );
    }
    return normalizePrimitive(define);
  };
  return normalizeObject(define);
};

template<bool VALUE>
Optional<size_t> find_first() const
{
    size_t byte_count = size_in_bytes();
    size_t i = 0;
    u8 byte = VALUE ? 0x00 : 0xff;
    while (i < byte_count && m_data[i] == byte)
        i++;
    if (i == byte_count)
        return {};
    byte = m_data[i];
    if constexpr (!VALUE)
        byte = ~byte;
    VERIFY(byte != 0);
    return i * 8 + bit_scan_forward(byte) - 1;
}

