export function getNGrams(
  words: string[],
  n: number
): string[] {
  if (n <= 0 || n > words.length) {
    return [];
  }

  const ngrams: string[] = [];
  for (let i = 0; i <= words.length - n; i++) {
    ngrams.push(words.slice(i, i + n).join(' '));
  }
  return ngrams;
}

compressHistory(
  threshold: number,
  keepCount: number
): boolean {
  if (this.messages.length <= threshold) {
    return false;
  }

  const omittedCount =
    this.messages.length - keepCount;
  const omittedPlaceholder: ChatCompletionMessageParam = {
    role: 'user',
    content:
      `(${omittedCount} previous conversation ` +
      `messages have been omitted)`,
  };

  const recentMessages =
    this.messages.slice(-keepCount);

  this.messages.length = 0;
  this.messages.push(omittedPlaceholder);
  for (const msg of recentMessages) {
    this.messages.push(msg);
  }

  return true;
}

